import React, { useState } from 'react';
import { Link } from 'react-router-dom';
import Discussion from '../components/Discussion';
import './Courses.css';

const Courses = () => {
  const [activeTab, setActiveTab] = useState('all');
  const [menuOpen, setMenuOpen] = useState(false);

  const courses = [
    {
      id: 1,
      title: 'Wildlife Conservation Basics',
      description: 'Learn the fundamentals of wildlife conservation and ecosystem management.',
      image: '/course-conservation.jpg',
      difficulty: 'beginner'
    },
    {
      id: 2,
      title: 'Advanced Anti-Poaching Techniques',
      description: 'Master modern anti-poaching strategies and technologies.',
      image: '/course-antipoaching.jpg',
      difficulty: 'advanced'
    },
    {
      id: 3,
      title: 'Community-Based Conservation',
      description: 'Explore effective methods for engaging local communities in conservation efforts.',
      image: '/course-community.jpg',
      difficulty: 'intermediate'
    }
  ];

  const toggleMenu = () => {
    setMenuOpen(!menuOpen);
  };

  const handleMenuClick = (tab) => {
    setActiveTab(tab);
    setMenuOpen(false);
  };

  const getFilteredCourses = () => {
    if (activeTab === 'all') return courses;
    if (activeTab === 'beginner') return courses.filter(c => c.difficulty === 'beginner');
    if (activeTab === 'intermediate') return courses.filter(c => c.difficulty === 'intermediate');
    if (activeTab === 'advanced') return courses.filter(c => c.difficulty === 'advanced');
    return courses;
  };

  return (
    <div className="courses-page">
      <div className="courses-hero">
        <h1>Wildlife Education Courses</h1>
        <p>Expand your knowledge and contribute to wildlife conservation</p>
      </div>

      <div className="courses-container">
        <div className={`course-filters ${menuOpen ? 'open' : ''}`}>
          <div className="filter-toggle" onClick={toggleMenu}>
            <span>Filter Courses</span>
            <div className="hamburger">
              <div></div>
              <div></div>
              <div></div>
            </div>
          </div>
          <ul className="filter-options">
            <li 
              className={activeTab === 'all' ? 'active' : ''}
              onClick={() => handleMenuClick('all')}
            >
              All Courses
            </li>
            <li 
              className={activeTab === 'beginner' ? 'active' : ''}
              onClick={() => handleMenuClick('beginner')}
            >
              Beginner
            </li>
            <li 
              className={activeTab === 'intermediate' ? 'active' : ''}
              onClick={() => handleMenuClick('intermediate')}
            >
              Intermediate
            </li>
            <li 
              className={activeTab === 'advanced' ? 'active' : ''}
              onClick={() => handleMenuClick('advanced')}
            >
              Advanced
            </li>
          </ul>
        </div>

        <div className="courses-grid">
          {getFilteredCourses().map(course => (
            <div key={course.id} className="course-card">
              <div className="course-image-container">
                <img src={course.image} alt={course.title} className="course-image" />
                <span className={`difficulty ${course.difficulty}`}>
                  {course.difficulty.charAt(0).toUpperCase() + course.difficulty.slice(1)}
                </span>
              </div>
              <div className="course-content">
                <h2>{course.title}</h2>
                <p className="course-description">{course.description}</p>
                <Link to={`/course/${course.id}`} className="enroll-button">
                  Enroll Now
                </Link>
              </div>
            </div>
          ))}
        </div>

        <Discussion pageId="courses" title="Courses" />
      </div>
    </div>
  );
};

export default Courses;
